#include <ESP8266WiFi.h>
// Include ESP8266 HTTP Client library
#include <ESP8266HTTPClient.h>

// Define your WiFi credentials and API keys as constants
const char* ssid = "Your_SSID";  // Replace with your SSID
const char* password = "Your_Password";  // Replace with your password
const char* apiKey = "Your_API_Secret_Key";  // Replace with your API Secret Key

void setup() {
  Serial.begin(115200);
  
  WiFi.mode(WIFI_STA);
  WiFi.begin(ssid, password);
  
  while (WiFi.status() != WL_CONNECTED) {
    delay(500);
    Serial.println("Connecting to WiFi...");
  }
}

void loop() {
  if (WiFi.status() == WL_CONNECTED) { // Check the current status of WiFi connection
  
    HTTPClient http;
    
    String serverPath = "http://iot.example.com/api?key=";
    serverPath += apiKey; 
    
    http.begin(serverPath); // Specify request destination
    
    int responseCode = http.GET(); // Send the request and get a response

    if (responseCode > 0) { //Check for the returning code
      String payload = http.getString();   // Get the request response payload
      Serial.println(payload);                     // Print the response payload
      
      int statusCode = http.getStatusCode();        // Extract HTTP return code
    }
    
    else { 
      Serial.printf("Error code: %d\n", responseCode);
    }
  
    http.end(); //Free up resources
  }

  delay(5000); // Wait for 5 seconds before the next call
}